  var c_val = 0.0; // cell state for this unit

  // Weight base offsets for this direction
  // W: [num_dir, IS, 4H] — flat stride: dir * IS * H4
  // R: [num_dir, H, 4H]  — flat stride: dir * H * H4
  let w_base = safe_dir * IS * H4;
  let r_base = safe_dir * H * H4;

